206→            }
207→        } catch {
208→            throw new Error("error updating profile");
209→        } finally {
210→            setIsUpdatingProfileConfig(false);
211→            setGradientPicked(null);
212→            setImageSrc(null);
213→            setShowBgPicker(false);
